INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_diff_401','デジタルヘルスパスポート採用研究','Digital Health Passport Adoption Research','COVID-19ワクチン接種証明・陰性証明などデジタルヘルスパスポートへの市民・事業者採用を分析した研究群。プライバシー・差別懸念・標準化不足・国際相互承認が採用規定因として確認されている。','国際渡航政策とヘルスデータガバナンス設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタルヘルス証明採用研究','2021','meso','adoption','health_credential_adoption','["Morley, J.", "Cowls, J.", "Taddeo, M."]','["Morley et al. (2021) Digital health passport ethics", "WHO (2021) Smart Vaccination Certificate"]','デジタルヘルスパスポート,ワクチン証明,プライバシー,国際標準','digital health passport,vaccine certificate,privacy,international standard'),
('inno_diff_402','再生医療製品採用の病院研究','Hospital Research on Regenerative Medicine Product Adoption','iPS細胞・CAR-T細胞療法・組織工学製品の病院採用を分析した研究群。製造コスト・凍結保存物流・保険償還未整備・患者選択基準が採用規定因として確認されている。','再生医療政策と先端医療の保険適用決定に実証的根拠を提供した。','diffusion_adoption_user','C_processes','再生医療採用研究','2017','meso','adoption','advanced_therapy_adoption','["Abou-El-Enein, M.", "Elsanhoury, A.", "Reinke, P."]','["Abou-El-Enein et al. (2021) CAR-T adoption barriers", "Reinke (2018) Cell therapy manufacturing"]','再生医療,CAR-T,iPS細胞,先端医療採用','regenerative medicine,CAR-T,iPS cells,advanced therapy adoption'),
('inno_diff_403','デジタルツールのカスタマーセルフサービス採用研究','Customer Self-Service Digital Tool Adoption Research','セルフチェックイン・セルフオーダー・AIチャットボットサポートへの消費者採用を分析した研究群。待ち時間短縮・操作エラーへの不安・人間対話の選好・企業への信頼が採用規定因として確認されている。','小売・ホスピタリティ・航空産業のセルフサービス化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','セルフサービス採用研究','2010','micro','adoption','self_service_adoption','["Bitner, M.J.", "Meuter, M.L.", "Curran, J.M."]','["Meuter et al. (2000) Self-service technology", "Curran & Meuter (2005) Self-service tech adoption"]','セルフサービス,チャットボット,セルフチェックイン,消費者採用','self-service,chatbot,self-check-in,consumer adoption'),
('inno_diff_404','環境センシング技術採用の市民科学研究','Citizen Science Research on Environmental Sensing Technology Adoption','大気質センサー・水質モニター・騒音計など市民科学用環境センサーへの一般市民採用を分析した研究群。データ品質への信頼・コスト・設置容易性・コミュニティ帰属感が採用規定因として確認されている。','環境政策のデータ民主化と市民科学プラットフォーム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','市民科学採用研究','2014','micro','adoption','citizen_science_adoption','["Bonney, R.", "Cooper, C.B.", "Dickinson, J."]','["Bonney et al. (2009) Citizen science", "Cooper et al. (2014) Citizen science environmental"]','市民科学,環境センサー,大気質モニター,参加型調査','citizen science,environmental sensor,air quality monitor,participatory research'),
('inno_diff_405','組み込みAI（エッジAI）採用の製造研究','Manufacturing Research on Embedded AI (Edge AI) Adoption','デバイスローカルで推論するエッジAI・組み込みMLの製造現場採用を分析した研究群。クラウド依存排除・リアルタイム処理需要・エッジデバイスコスト・モデル更新管理が採用規定因として確認されている。','製造業のIoT-AI統合戦略と産業セキュリティ政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','エッジAI採用研究','2020','meso','adoption','edge_computing_adoption','["Shi, W.", "Cao, J.", "Zhang, Q."]','["Shi et al. (2016) Edge computing opportunities", "Cao et al. (2020) Edge AI survey"]','エッジAI,組み込みAI,エッジコンピューティング,製造AI','edge AI,embedded AI,edge computing,manufacturing AI'),
('inno_diff_406','植物性タンパク採用の食品産業研究','Food Industry Research on Plant-Based Protein Adoption','Beyond Meat・Impossible Foodsなど植物性代替肉の食品企業・飲食チェーン採用を分析した研究群。原材料コスト・食感再現技術・消費者受容・ブランドリスクが採用規定因として確認されている。','フードテック産業政策と持続可能な食料システム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','代替タンパク食品採用研究','2018','meso','adoption','sustainable_food_adoption','["Slade, P.", "Wilks, M.", "Ismail, I."]','["Slade (2018) Clean meat overview", "Wilks & Phillips (2017) Consumer plant-based protein"]','植物性タンパク,代替肉,食品産業採用,フードテック','plant-based protein,meat alternatives,food industry adoption,foodtech'),
('inno_diff_407','デジタル公共サービス採用の移民研究','Immigrant Research on Digital Public Service Adoption','外国人居住者・移民による電子政府・デジタル行政サービスへの採用を分析した研究群。言語バリア・文化的行政規範差異・ネット接続格差・手続き複雑性が採用障壁として確認されている。','移民統合政策とデジタル包摂戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','移民デジタル採用研究','2015','micro','adoption','cultural_language_adoption_barrier','["Komito, L.", "Bates, J.", "Torres, A."]','["Komito & Bates (2011) Irish immigrants ICT", "Torres et al. (2013) Immigrant digital barriers"]','移民,デジタル行政,言語バリア,デジタル包摂','immigrants,digital public services,language barrier,digital inclusion'),
('inno_diff_408','遠隔介護監視システム採用研究','Remote Eldercare Monitoring System Adoption Research','カメラ・センサー・AIによる高齢者遠隔見守りシステムへの家族・施設採用を分析した研究群。プライバシー・尊厳・家族安心感・誤警報率が採用規定因として確認されている。倫理的監視と安全の緊張関係が重要テーマとなっている。','高齢者ケア政策と介護DX推進に実証的根拠を提供した。','diffusion_adoption_user','C_processes','遠隔介護採用研究','2016','micro','adoption','surveillance_care_adoption','["Demiris, G.", "Rantz, M.J.", "Aud, M.A."]','["Demiris et al. (2004) Smart home sensors elderly", "Rantz et al. (2013) Intelligent systems aging"]','遠隔見守り,介護監視,プライバシー,高齢者ケア','remote monitoring,eldercare surveillance,privacy,elderly care'),
('inno_diff_409','先端運転支援システム（ADAS）採用研究','Advanced Driver Assistance System Adoption Research','車線逸脱警告・自動緊急ブレーキ・アダプティブクルーズコントロールへの消費者採用を分析した研究群。安全効果への信頼・誤作動への苛立ち・過信リスク・価格が採用規定因として確認されている。','自動車安全規制と自動運転移行政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ADAS採用研究','2014','micro','adoption','safety_technology_adoption','["Natarajan, M.", "Mikulski, J.", "Noy, Y.I."]','["Noy et al. (2018) ADAS adoption study", "Mikulski (2012) Driver assistance systems"]','ADAS,自動緊急ブレーキ,車線逸脱警告,運転支援採用','ADAS,automatic emergency braking,lane departure warning,driver assistance adoption'),
('inno_diff_410','スポーツ計測技術採用の審判・競技団体研究','Referee and Sports Governing Body Research on Sports Measurement Technology Adoption','VAR（ビデオ判定）・ホークアイ・チップインボール等スポーツ計測技術の審判・競技団体採用を分析した研究群。競技の流れへの影響・判定精度・費用・競技の公正性認知が採用規定因として確認されている。','スポーツルール策定と競技技術規制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','スポーツテクノロジー採用研究（審判）','2015','meso','adoption','game_integrity_adoption','["Hawk-Eye (2001)", "Wimbledon ITF", "FIFA VAR"]','["FIFA (2018) VAR implementation report", "ITF (2006) Hawk-Eye review"]','VAR,ホークアイ,スポーツ計測,審判技術','VAR,Hawk-Eye,sports measurement,referee technology'),
('inno_diff_411','オープンサイエンスツール採用の研究コミュニティ研究','Research Community Adoption of Open Science Tools','OSF・Zenodo・preregistration・GitHub-for-science等オープンサイエンスツールへの研究者採用を分析した研究群。再現性危機への危機感・キャリアインセンティブ・追加作業負担・共有デフォルト規範の欠如が採用規定因として確認されている。','オープンサイエンス政策と学術評価制度改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','オープンサイエンス採用研究','2015','micro','adoption','open_norms_adoption','["Nosek, B.A.", "Munafò, M.R.", "Simmons, J.P."]','["Nosek et al. (2015) Estimating reproducibility", "Munafò et al. (2017) Manifesto for reproducible science"]','オープンサイエンス,再現性,preregistration,研究ツール採用','open science,reproducibility,preregistration,research tool adoption'),
('inno_diff_412','スマートプロソーシャル行動支援技術採用研究','Pro-Social Behavior Support Technology Adoption Research','食品ロス削減アプリ・フードシェアリングプラットフォーム・カーボントラッカーへの消費者採用を分析した研究群。社会規範・フィードバック可視化・ゲーミフィケーション・自己効力感が採用規定因として確認されている。','持続可能な消費行動政策とナッジ設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','プロソーシャル技術採用研究','2017','micro','adoption','prosocial_nudge_adoption','["Thøgersen, J.", "Nolan, J.M.", "Cialdini, R.B."]','["Thøgersen (2004) A cognitive dissonance model", "Nolan et al. (2008) Misperceived social norms"]','食品ロス削減,フードシェア,カーボントラッカー,プロソーシャル','food waste reduction,food sharing,carbon tracker,pro-social'),
('inno_diff_413','廃水処理技術採用の水道事業者研究','Water Utility Research on Wastewater Treatment Technology Adoption','膜生物反応器（MBR）・高度酸化処理・再生水利用技術の水道事業者採用を分析した研究群。規制適合コスト・技術習熟期間・エネルギー消費・ライフサイクルコストが採用規定因として確認されている。','水再利用政策と水安全保障戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','水処理技術採用研究','2008','meso','adoption','water_technology_adoption','["Judd, S.J.", "Jefferson, B.", "Stephenson, T."]','["Judd (2008) MBR technology", "Jefferson et al. (2000) MBR for water reuse"]','廃水処理,MBR,再生水,水道事業者採用','wastewater treatment,MBR,water reuse,water utility adoption'),
('inno_diff_414','デジタルミュージック配信採用研究（アーティスト視点）','Artist-Perspective Research on Digital Music Distribution Adoption','Spotify・Apple Music・Bandcamp等デジタル音楽配信サービスへのアーティスト採用を分析した研究群。収益配分・著作権管理・ファン直接接続・アルゴリズム可視化が採用規定因として確認されている。','音楽産業の構造変革政策と著作権制度改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','デジタル音楽採用研究','2013','micro','adoption','artist_platform_adoption','["Wikström, P.", "Marshall, L.", "Hracs, B.J."]','["Wikström (2013) Music Industry", "Marshall (2015) Music and copyright"]','デジタル音楽配信,Spotify,アーティスト採用,著作権','digital music distribution,Spotify,artist adoption,copyright'),
('inno_diff_415','拡張現実ナビゲーション採用研究','Augmented Reality Navigation Adoption Research','Google Maps AR・Apple Maps AR・屋内ARナビへの採用を分析した研究群。視覚的没入感・歩行中の安全性・バッテリー消費・デザイン洗練度が採用規定因として確認されている。','モバイルAR製品設計とスマートシティナビゲーション政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ARナビゲーション採用研究','2018','micro','adoption','ar_navigation_adoption','["Reitmayr, G.", "Schmalstieg, D.", "Ens, B."]','["Reitmayr & Schmalstieg (2003) AR navigation", "Ens et al. (2014) Around device AR"]','ARナビゲーション,拡張現実地図,屋内ナビ,スマートシティ','AR navigation,augmented reality maps,indoor navigation,smart city'),
('inno_diff_416','モジュラー建築採用研究','Modular Construction Adoption Research','プレファブ・ユニット建築・3Dプリント住宅の建設会社・住宅デベロッパー採用を分析した研究群。設計自由度の制限・建設許可対応・サプライチェーン安定性・品質管理が採用規定因として確認されている。','住宅政策と建設産業の生産性向上戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','モジュラー建築採用研究','2015','meso','adoption','prefab_adoption','["Blismas, N.", "Pasquire, C.", "Gibb, A."]','["Blismas et al. (2006) Prefabrication benefits", "Gibb (1999) Off-site fabrication"]','モジュラー建築,プレファブ,3Dプリント住宅,住宅DX','modular construction,prefabrication,3D printed housing,housing DX'),
('inno_diff_417','デジタル処方薬採用研究（eRx）','Electronic Prescription Adoption Research','電子処方箋（eRx）・処方データシェア・調剤自動化システムへの医師・薬局採用を分析した研究群。電子カルテ統合・法的認証基盤・プライバシー規制・慣習変更抵抗が採用規定因として確認されている。','薬局DX政策と医薬品安全管理に実証的根拠を提供した。','diffusion_adoption_user','C_processes','電子処方採用研究','2009','meso','adoption','eprescription_adoption','["Grossman, J.M.", "Boukus, E.R.", "Cross, D.A."]','["Grossman et al. (2009) eRx adoption", "Cross et al. (2010) Electronic prescribing adoption"]','電子処方箋,eRx,薬局DX,処方データ','electronic prescription,eRx,pharmacy DX,prescription data'),
('inno_diff_418','デジタル音声アシスタント採用の車内研究','In-Vehicle Research on Digital Voice Assistant Adoption','CarPlay・Android Auto・車載音声コマンドへの採用を分析した研究群。運転中の安全性・音声認識精度・ナビゲーション精度・プラットフォーム互換性が採用規定因として確認されている。','車載インフォテインメント政策と自動車産業のデジタル化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','車載AI採用研究','2016','micro','adoption','in_vehicle_adoption','["Narayanan, V.", "Mirnig, A.G.", "Wilfinger, D."]','["Narayanan et al. (2018) Voice assistant car", "Mirnig & Wilfinger (2015) In-car UI"]','車内音声アシスタント,CarPlay,Android Auto,車載インフォテインメント','in-vehicle voice assistant,CarPlay,Android Auto,infotainment'),
('inno_diff_419','ストリーミング教育コンテンツ採用研究','Streaming Educational Content Adoption Research','YouTube Learning・Khan Academy・TED-Ed・NHK for SchoolなどOER（オープン教育リソース）ストリーミングへの学習者採用を分析した研究群。コンテンツ品質・検索性・字幕対応・学習の継続性が採用規定因として確認されている。','オープン教育資源政策と非公式学習環境の設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','ストリーミング学習採用研究','2012','micro','adoption','informal_learning_adoption','["Buckingham Shum, S.", "Ferguson, R.", "Clow, D."]','["Ferguson (2012) Learning analytics", "Clow (2013) MOOC funnels"]','ストリーミング学習,OER,Khan Academy,非公式学習','streaming education,OER,Khan Academy,informal learning'),
('inno_diff_420','食料廃棄削減アプリ採用研究','Food Waste Reduction App Adoption Research','Too Good To Go・Olio・フードシェアリングアプリへの消費者採用を分析した研究群。食品廃棄への罪悪感・価格インセンティブ・利便性・食品安全懸念が採用規定因として確認されている。','食品ロス政策と循環型食料システム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','食品ロス削減採用研究','2017','micro','adoption','guilt_motivated_adoption','["Schanes, K.", "Dobernig, K.", "Gözet, B."]','["Schanes et al. (2018) Food waste review", "Gözet et al. (2020) Food sharing app"]','食料廃棄,フードシェアリング,Too Good To Go,食品ロス','food waste,food sharing,Too Good To Go,food loss'),
('inno_diff_421','デジタルノーテイキング採用研究','Digital Note-Taking Adoption Research','Notion・Obsidian・Roam Research・Apple Notesへのナレッジワーカー採用を分析した研究群。知識接続性・PKM（個人知識管理）哲学・プラットフォーム乗り換えコスト・オフライン利用が採用規定因として確認されている。','個人知識管理ツール市場と組織学習システム設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','PKMツール採用研究','2018','micro','adoption','pkm_adoption','["Ahrens, S.", "Forte, A.", "Luhmann, N."]','["Ahrens (2017) How to Take Smart Notes", "Forte (2022) Building a Second Brain"]','デジタルノーテイキング,PKM,Notion,Obsidian','digital note-taking,PKM,Notion,Obsidian'),
('inno_diff_422','グリーン建築技術採用研究（ZEB・ZEH）','Green Building Technology Adoption Research: ZEB and ZEH','ゼロエネルギービル・ゼロエネルギーハウスへの建設会社・デベロッパー採用を分析した研究群。初期コストプレミアム・認証取得負担・エネルギーシミュレーション精度・テナント需要が採用規定因として確認されている。','建築物省エネ政策と不動産産業の持続可能性戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','グリーン建築採用研究','2012','meso','adoption','green_building_adoption','["Kibert, C.J.", "Häkkinen, T.", "Vares, S."]','["Kibert (2012) Sustainable construction", "Häkkinen & Belloni (2011) Barriers green building"]','ZEB,ZEH,ゼロエネルギー建築,グリーンビルディング','ZEB,ZEH,zero energy building,green building'),
('inno_diff_423','COVID-19接触確認アプリ採用研究','COVID-19 Contact Tracing App Adoption Research','COCOA・StopCovid・NHS COVID-19等接触確認アプリへの市民採用を分析した研究群。プライバシー・政府信頼・有効性認知・スマートフォン所持率が採用規定因として確認されている。国際比較研究が特に蓄積されている。','パンデミック対応デジタルツール政策と公衆衛生倫理設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','パンデミック対応採用研究','2020','meso','adoption','public_health_trust_adoption','["Trang, S.", "Trenz, M.", "Weiger, W.H."]','["Trang et al. (2020) Contact tracing apps adoption", "Morley et al. (2020) COVID-19 contact tracing ethics"]','接触確認アプリ,COVID-19,プライバシー,公衆衛生','contact tracing app,COVID-19,privacy,public health'),
('inno_diff_424','サイバーフィジカルセキュリティ採用研究','Cyber-Physical Security Technology Adoption Research','OT/ICSセキュリティ・産業用ファイアウォール・ゼロトラスト産業ネットワークへの製造・エネルギー企業採用を分析した研究群。IT/OT融合の複雑性・レガシーPLC・運用中断リスク・セキュリティベンダー信頼が採用規定因として確認されている。','重要インフラ保護政策と産業セキュリティ規制に実証的根拠を提供した。','diffusion_adoption_user','C_processes','産業サイバーセキュリティ採用研究','2017','meso','adoption','critical_infrastructure_adoption','["Lee, R.M.", "Kaspersky, E.", "Stouffer, K."]','["Lee (2014) ICS security", "Stouffer et al. (2015) NIST ICS security guide"]','OTセキュリティ,ICS,重要インフラ,産業セキュリティ','OT security,ICS,critical infrastructure,industrial security'),
('inno_diff_425','テレスコピック医療採用研究（遠隔手術・遠隔診断）','Telescopic Medicine Adoption Research: Remote Surgery and Remote Diagnostics','5G超低遅延を活用した遠隔手術・遠隔神経科診断・テレリハビリへの医師・病院採用を分析した研究群。レイテンシ要件・法的責任・医師免許の地理的制限・機器標準化が採用規定因として確認されている。','遠隔医療法制改革と5Gヘルスケアインフラ政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','遠隔高度医療採用研究','2019','meso','adoption','telesurgery_adoption','["Avgousti, S.", "Christoforou, E.G.", "Panayides, A.S."]','["Avgousti et al. (2016) Telesurgery review", "Panayides et al. (2019) AI stroke telemedicine"]','遠隔手術,テレサージェリー,遠隔診断,5G医療','telesurgery,remote surgery,remote diagnostics,5G healthcare'),
('inno_diff_426','生物多様性クレジット採用研究','Biodiversity Credit Adoption Research','自然資本クレジット・生物多様性オフセット・ネイチャーポジティブ金融商品への企業・投資家採用を分析した研究群。生物多様性計測の困難さ・グリーンウォッシング懸念・基準の多様性・市場規模不足が採用規定因として確認されている。','TNFD・COP15昆明-モントリオール目標の実施と自然資本金融政策に貢献した。','diffusion_adoption_user','C_processes','自然資本採用研究','2021','meso','adoption','nature_positive_adoption','["Dasgupta, P.", "Paulson, S.", "Sumaila, U.R."]','["Dasgupta (2021) Biodiversity review", "TNFD (2023) Nature-related risk framework"]','生物多様性クレジット,自然資本,ネイチャーポジティブ,TNFD','biodiversity credit,natural capital,nature positive,TNFD'),
('inno_diff_427','デジタルサプライチェーン金融採用研究','Digital Supply Chain Finance Adoption Research','Fintech SCF・動的割引・電子インボイス・ブロックチェーン貿易金融への企業採用を分析した研究群。バイヤー信用力・承認プロセス複雑性・ITシステム統合・規制適合が採用規定因として確認されている。','サプライチェーン金融政策と貿易金融デジタル化戦略に実証的根拠を提供した。','diffusion_adoption_user','C_processes','SCFデジタル採用研究','2016','meso','adoption','trade_finance_adoption','["Wuttke, D.A.", "Blome, C.", "Henke, M."]','["Wuttke et al. (2013) Supply chain finance", "Blome et al. (2014) Dynamic discounting"]','サプライチェーン金融,動的割引,電子インボイス,貿易金融','supply chain finance,dynamic discounting,e-invoice,trade finance'),
('inno_diff_428','AIによる法執行技術採用研究（顔認識・予測警察）','Law Enforcement AI Technology Adoption Research: Facial Recognition and Predictive Policing','顔認識システム・犯罪予測AIへの警察・行政採用と市民受容を分析した研究群。人種差別バイアス・誤認逮捕リスク・令状手続き適合・監視社会懸念が採用規定因として確認されている。EU AI Actの禁止・制限対象としての規制論争も含まれる。','法執行AI規制政策と市民権保護制度設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','法執行AI採用研究','2018','meso','adoption','surveillance_adoption','["Ferguson, A.G.", "Garvie, C.", "Brayne, S."]','["Ferguson (2017) Rise of Big Data policing", "Garvie et al. (2016) Perpetual lineup"]','顔認識AI,予測警察,監視技術,バイアス問題','facial recognition AI,predictive policing,surveillance technology,algorithmic bias'),
('inno_diff_429','持続可能航空燃料（SAF）採用研究','Sustainable Aviation Fuel Adoption Research','SAF（持続可能航空燃料）への航空会社採用を分析した研究群。製造コスト・供給量不足・規制インセンティブ（CORSIA）・機体認証が採用規定因として確認されている。','航空産業の脱炭素政策と代替燃料インフラ投資計画に実証的根拠を提供した。','diffusion_adoption_user','C_processes','SAF採用研究','2020','meso','adoption','aviation_decarbonization_adoption','["Pavlenko, N.", "Searle, S.", "Kharina, A."]','["Pavlenko et al. (2019) SAF report", "IATA (2021) SAF roadmap"]','SAF,持続可能航空燃料,CORSIA,航空脱炭素','SAF,sustainable aviation fuel,CORSIA,aviation decarbonization'),
('inno_diff_430','工業用メタバース採用研究','Industrial Metaverse Adoption Research','Nvidia Omniverse・Siemens Xcelerator等工業用メタバース・デジタルツイン-メタバース統合への製造企業採用を分析した研究群。リアルタイム物理シミュレーション精度・帯域幅・専門人材・ROI不確実性が採用規定因として確認されている。','製造業の次世代デジタル化戦略と産業プラットフォーム競争政策に貢献した。','diffusion_adoption_user','C_processes','工業用メタバース採用研究','2022','meso','adoption','industrial_metaverse_adoption','["Nvidia", "Siemens", "Grieves, M."]','["Grieves (2022) Industrial metaverse concept", "Siemens (2022) Industrial metaverse whitepaper"]','工業用メタバース,デジタルツイン,製造DX,Nvidia Omniverse','industrial metaverse,digital twin,manufacturing DX,Nvidia Omniverse'),
('inno_diff_431','航空宇宙製造採用研究（複合材・AM）','Aerospace Manufacturing Adoption Research: Composites and AM','炭素繊維複合材・チタンAM部品・セラミック複合材のエアバス・ボーイング・JAXAでの採用を分析した研究群。認証プロセス・材料再現性・NDT（非破壊検査）・設計変更コストが採用規定因として確認されている。','航空宇宙産業の軽量化・脱炭素政策と素材技術標準化に実証的根拠を提供した。','diffusion_adoption_user','C_processes','航空宇宙製造採用研究','2010','meso','adoption','aerospace_material_adoption','["Soutis, C.", "Campbell, J.", "Mouritz, A.P."]','["Soutis (2005) Carbon fiber composites aerospace", "Campbell (2012) Structural composite materials"]','炭素繊維複合材,航空宇宙製造,AM部品,NDT','carbon fiber composites,aerospace manufacturing,AM parts,NDT'),
('inno_diff_432','マイクログリッド採用研究','Microgrid Adoption Research','島嶼・農村・都市マイクログリッドシステムへの電力会社・自治体・企業採用を分析した研究群。分散電源調整・系統連系規制・スマートコントロール技術・エネルギー安全保障動機が採用規定因として確認されている。','分散型電力システム政策と電力規制改革に実証的根拠を提供した。','diffusion_adoption_user','C_processes','マイクログリッド採用研究','2014','meso','adoption','distributed_energy_adoption','["Hirsch, A.", "Parag, Y.", "Guerrero, J."]','["Hirsch et al. (2018) Microgrids review", "Guerrero et al. (2013) Advanced control microgrids"]','マイクログリッド,分散電源,系統連系,エネルギー安全保障','microgrid,distributed energy,grid connection,energy security'),
('inno_diff_433','パーソナルAIエージェント採用研究','Personal AI Agent Adoption Research','AutoGPT・Devin・Operator等パーソナルAIエージェントへの個人・企業採用を分析した研究群。タスク自律性への信頼・ミスのリスク許容・プライバシー・コスト・スキル代替への不安が採用規定因として確認されている。生成AI第二世代としての研究が急増している。','AIエージェント規制政策と企業の業務自動化戦略に実証的根拠を提供している。','diffusion_adoption_user','C_processes','AIエージェント採用研究','2023','micro','adoption','ai_agent_adoption','["Wooldridge, M.", "Russell, S.", "Anthropic, OpenAI"]','["Wooldridge (1999) Intelligent Agents", "Russell (2022) AI safety agent"]','AIエージェント,AutoGPT,タスク自動化,信頼','AI agent,AutoGPT,task automation,trust'),
('inno_diff_434','核融合エネルギー採用の初期市場研究','Early Market Research on Fusion Energy Adoption','Commonwealth Fusion Systems・TAE Technologies等核融合スタートアップのパイロット採用を分析した研究群。技術成熟度（TRL2-4）・長期投資回収・規制フレームワーク不在・人材確保が採用規定因として確認されている。','核融合エネルギー産業政策と長期エネルギーロードマップ設計に初期知見を提供した。','diffusion_adoption_user','C_processes','核融合採用初期研究','2021','macro','adoption','deep_tech_adoption','["Clery, D.", "Cowley, S.C.", "Whyte, D."]','["Clery (2013) A piece of the sun", "Cowley (2016) Fusion energy roadmap"]','核融合,核融合エネルギー採用,Deep Tech,長期エネルギー','nuclear fusion,fusion energy adoption,deep tech,long-term energy'),
('inno_diff_435','保険×テレマティクスの高齢者採用研究','Elderly Adoption Research on Insurance Telematics','高齢ドライバーを対象とした運転行動連動型保険（テレマティクスUBI）への採用を分析した研究群。プライバシー・運転自由制限への不安・スマートフォン操作不安・保険料低減期待が採用規定因として確認されている。','高齢者交通安全政策とテレマティクス保険設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','高齢者UBI採用研究','2018','micro','adoption','elderly_ubi_adoption','["Langford, J.", "Koppel, S.", "Charlton, J."]','["Langford & Koppel (2006) Older driver safety", "Charlton et al. (2020) UBI elderly"]','高齢ドライバー,UBI,テレマティクス保険,交通安全','elderly driver,UBI,telematics insurance,traffic safety'),
('inno_diff_436','衛星測位技術採用研究（GNSS・RTK）','GNSS and RTK Satellite Positioning Technology Adoption Research','農業・建設・物流・測量でのRTK-GNSS・PPP高精度測位への採用を分析した研究群。精度保証・補正信号コスト・マルチパス環境対応・利用規制が採用規定因として確認されている。','精密農業・自動建設・自動運転インフラ整備に実証的根拠を提供した。','diffusion_adoption_user','C_processes','精密測位採用研究','2010','meso','adoption','precision_positioning_adoption','["Langley, R.B.", "Rizos, C.", "Leick, A."]','["Leick et al. (2015) GPS satellite surveying", "Rizos (2010) GNSS positioning"]','GNSS,RTK,高精度測位,精密農業','GNSS,RTK,high-precision positioning,precision agriculture'),
('inno_diff_437','カーボンフットプリント計算ツール採用研究','Carbon Footprint Calculation Tool Adoption Research','企業・個人向けCO2排出量計算ツール・スコープ3排出量管理プラットフォームへの採用を分析した研究群。データ入手難易度・会計標準（GHGプロトコル）適合・外部審査コスト・サプライヤー協力が採用規定因として確認されている。','企業脱炭素戦略とGHG開示規制（ISSB・CSRD）に実証的根拠を提供した。','diffusion_adoption_user','C_processes','カーボン管理ツール採用研究','2019','meso','adoption','ghg_accounting_adoption','["Wiedmann, T.", "Minx, J.", "Hertwich, E."]','["Wiedmann & Minx (2008) Carbon footprint definition", "Hertwich & Peters (2009) Carbon footprint consumption"]','カーボンフットプリント,スコープ3,GHG開示,脱炭素','carbon footprint,Scope 3,GHG disclosure,decarbonization'),
('inno_diff_438','AIによる医薬品候補探索採用研究','AI Drug Discovery Adoption Research','AlphaFold2・Schrödinger・Insilico MedicineなどAI創薬ツールへの製薬企業採用を分析した研究群。化合物ライブラリ統合・規制当局との合意・臨床転換率検証・人材確保が採用規定因として確認されている。','製薬研究開発戦略とAI創薬規制設計に実証的根拠を提供した。','diffusion_adoption_user','C_processes','AI創薬採用研究','2020','meso','adoption','ai_drug_discovery_adoption','["Jumper, J.", "Schneider, G.", "Zhavoronkov, A."]','["Jumper et al. (2021) AlphaFold2", "Schneider & Fechner (2005) Computer drug discovery"]','AI創薬,AlphaFold,タンパク質構造予測,製薬AI','AI drug discovery,AlphaFold,protein structure prediction,pharma AI'),
('inno_diff_439','オンライン食料品配達採用研究','Online Grocery Delivery Adoption Research','Amazon Fresh・Instacart・楽天マート等オンライン食料品配達への消費者採用を分析した研究群。鮮度不安・配達時間精度・価格割増・食品選択の楽しさ喪失が採用規定因として確認されている。COVID-19後の定着率も研究されている。','小売食料品産業のeコマース転換戦略と都市物流政策に実証的根拠を提供した。','diffusion_adoption_user','C_processes','オンライン食料品採用研究','2016','micro','adoption','online_grocery_adoption','["Melis, K.", "Campo, K.", "Breugelmans, E."]','["Melis et al. (2015) Switch to online grocery", "Campo & Breugelmans (2015) Buying groceries online"]','オンライン食料品,食料品配達,Amazon Fresh,鮮度不安','online grocery,grocery delivery,Amazon Fresh,freshness concern'),
('inno_diff_440','スマートウェアラブルの子ども向け採用研究','Children-Focused Smart Wearable Adoption Research','子ども向けGPS腕時計・健康トラッカー・スマートランドセルへの親・子どもの採用を分析した研究群。安全監視動機・プライバシー教育・デバイス耐久性・データ主体同意が採用規定因として確認されている。','子ども向けIoT規制と子どもデータプライバシー政策（COPPA等）に実証的根拠を提供した。','diffusion_adoption_user','C_processes','子どもウェアラブル採用研究','2016','micro','adoption','child_safety_adoption','["Mascheroni, G.", "Jorge, A.", "Farrugia, L."]','["Mascheroni & Ólafsson (2014) Children mobile internet", "Jorge (2020) Kids wearables"]','子ども向けGPS,スマートウェアラブル,COPPA,子どもプライバシー','children GPS,smart wearable,COPPA,children privacy');
